import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeRange,
  TimeRangePreset,
  TimeSeriesPoint,
  TopProduct,
} from '../models/analytics.js';
import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

/** Map preset strings to millisecond durations. */
const PRESET_DURATIONS: Record<TimeRangePreset, number> = {
  '24h': 24 * 60 * 60 * 1000,
  '7d': 7 * 24 * 60 * 60 * 1000,
  '30d': 30 * 24 * 60 * 60 * 1000,
  '90d': 90 * 24 * 60 * 60 * 1000,
};

const MS_PER_DAY = 24 * 60 * 60 * 1000;

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  // ─── Public API ──────────────────────────────────────────────────

  /**
   * Return the full dashboard payload for the given query.
   */
  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
    this.logger.info(`Generating dashboard for range: ${JSON.stringify(query)}`);

    const range = this.resolveTimeRange(query);
    const resolvedQuery: AnalyticsQuery = { ...query, range };

    const [metrics, ordersByStatus, topProducts] = await Promise.all([
      this.getAllMetrics(range),
      this.getOrderStatusBreakdown(range),
      this.getTopProducts(range),
    ]);

    return {
      query: resolvedQuery,
      metrics,
      ordersByStatus,
      topProducts,
      generatedAt: new Date(),
    };
  }

  /**
   * Return a single metric summary for the given type and time range.
   */
  async getMetric(type: MetricType, query: AnalyticsQuery): Promise<MetricSummary> {
    this.logger.info(`Computing metric: ${type}`);
    const range = this.resolveTimeRange(query);
    return this.computeMetric(type, range);
  }

  /**
   * Return order counts grouped by status within the given range.
   */
  async getOrderStatusBreakdown(range: TimeRange): Promise<OrderStatusBreakdown> {
    this.logger.info('Computing order status breakdown');
    const orders = this.getOrdersInRange(range);
    const breakdown: OrderStatusBreakdown = {
      pending: 0,
      confirmed: 0,
      shipped: 0,
      delivered: 0,
      cancelled: 0,
    };
    for (const order of orders) {
      breakdown[order.status]++;
    }
    return breakdown;
  }

  /**
   * Return the top products by revenue within the given range.
   *
   * @param range - Time range to filter orders
   * @param limit - Max number of products to return (default 10)
   */
  async getTopProducts(range: TimeRange, limit = 10): Promise<TopProduct[]> {
    this.logger.info('Computing top products');
    const orders = this.getOrdersInRange(range);
    const productMap = new Map<string, TopProduct>();

    for (const order of orders) {
      for (const item of order.items) {
        const existing = productMap.get(item.productId);
        if (existing) {
          existing.totalRevenue += item.quantity * item.unitPrice;
          existing.totalQuantity += item.quantity;
        } else {
          productMap.set(item.productId, {
            productId: item.productId,
            name: item.name,
            totalRevenue: item.quantity * item.unitPrice,
            totalQuantity: item.quantity,
          });
        }
      }
    }

    return Array.from(productMap.values())
      .sort((a, b) => b.totalRevenue - a.totalRevenue)
      .slice(0, limit);
  }

  // ─── Private Helpers ─────────────────────────────────────────────

  /**
   * Resolve an AnalyticsQuery into a concrete TimeRange.
   * Custom range takes precedence; otherwise fall back to preset (default '7d').
   */
  private resolveTimeRange(query: AnalyticsQuery): TimeRange {
    if (query.range) {
      return query.range;
    }
    const preset = query.preset ?? '7d';
    const end = new Date();
    const start = new Date(end.getTime() - PRESET_DURATIONS[preset]);
    return { start, end };
  }

  /**
   * Compute all four metric summaries in parallel.
   */
  private async getAllMetrics(range: TimeRange): Promise<MetricSummary[]> {
    const types: MetricType[] = ['revenue', 'orders', 'users', 'conversion'];
    return Promise.all(types.map((type) => this.computeMetric(type, range)));
  }

  /**
   * Compute a single metric's current value, previous-period value,
   * percent change, and time-series points.
   */
  private async computeMetric(type: MetricType, range: TimeRange): Promise<MetricSummary> {
    this.logger.info(`Computing metric: ${type}`);

    const previousRange = this.getPreviousRange(range);
    const orders = this.getOrdersInRange(range);
    const previousOrders = this.getOrdersInRange(previousRange);
    const users = this.getUsersInRange(range);
    const previousUsers = this.getUsersInRange(previousRange);

    let current: number;
    let previous: number;
    let series: TimeSeriesPoint[];

    switch (type) {
      case 'revenue': {
        current = this.sumOrderTotals(orders);
        previous = this.sumOrderTotals(previousOrders);
        series = this.buildDailySeries(range, orders, (dayOrders) =>
          this.sumOrderTotals(dayOrders),
        );
        break;
      }
      case 'orders': {
        current = orders.length;
        previous = previousOrders.length;
        series = this.buildDailySeries(range, orders, (dayOrders) => dayOrders.length);
        break;
      }
      case 'users': {
        current = users.length;
        previous = previousUsers.length;
        series = this.buildDailySeriesFromUsers(range, users);
        break;
      }
      case 'conversion': {
        current = users.length > 0 ? orders.length / users.length : 0;
        previous = previousUsers.length > 0 ? previousOrders.length / previousUsers.length : 0;
        series = this.buildDailyConversionSeries(range, orders, users);
        break;
      }
    }

    const changePercent = previous !== 0 ? ((current - previous) / previous) * 100 : 0;

    return { type, current, previous, changePercent, series };
  }

  /** Get orders with createdAt within [start, end). */
  private getOrdersInRange(range: TimeRange): Order[] {
    return this.orderRepository.findAll(
      (order) => order.createdAt >= range.start && order.createdAt < range.end,
    );
  }

  /** Get users with createdAt within [start, end). */
  private getUsersInRange(range: TimeRange): User[] {
    return this.userRepository.findAll(
      (user) => user.createdAt >= range.start && user.createdAt < range.end,
    );
  }

  /** Sum the total field across orders. */
  private sumOrderTotals(orders: Order[]): number {
    return orders.reduce((sum, order) => sum + order.total, 0);
  }

  /** Shift a range backward by its own duration for previous-period comparison. */
  private getPreviousRange(range: TimeRange): TimeRange {
    const duration = range.end.getTime() - range.start.getTime();
    return {
      start: new Date(range.start.getTime() - duration),
      end: new Date(range.start.getTime()),
    };
  }

  /** Generate UTC day bucket keys from start to end (inclusive of partial days). */
  private getDayBuckets(range: TimeRange): string[] {
    const buckets: string[] = [];
    const startDay = this.toDayKey(range.start);
    const endDay = this.toDayKey(new Date(range.end.getTime() - 1)); // end is exclusive
    let current = new Date(startDay + 'T00:00:00Z');
    const endDate = new Date(endDay + 'T00:00:00Z');
    while (current <= endDate) {
      buckets.push(this.toDayKey(current));
      current = new Date(current.getTime() + MS_PER_DAY);
    }
    return buckets;
  }

  /** Convert a Date to a UTC day string like '2024-01-15'. */
  private toDayKey(date: Date): string {
    return date.toISOString().slice(0, 10);
  }

  /** Build a daily time series from orders using an aggregator function. */
  private buildDailySeries(
    range: TimeRange,
    orders: Order[],
    aggregate: (dayOrders: Order[]) => number,
  ): TimeSeriesPoint[] {
    const buckets = this.getDayBuckets(range);
    const ordersByDay = new Map<string, Order[]>();
    for (const bucket of buckets) {
      ordersByDay.set(bucket, []);
    }
    for (const order of orders) {
      const key = this.toDayKey(order.createdAt);
      const dayOrders = ordersByDay.get(key);
      if (dayOrders) {
        dayOrders.push(order);
      }
    }
    return buckets.map((key) => ({
      timestamp: new Date(key + 'T00:00:00Z'),
      value: aggregate(ordersByDay.get(key) ?? []),
      label: key,
    }));
  }

  /** Build a daily time series of new user counts. */
  private buildDailySeriesFromUsers(range: TimeRange, users: User[]): TimeSeriesPoint[] {
    const buckets = this.getDayBuckets(range);
    const countByDay = new Map<string, number>();
    for (const bucket of buckets) {
      countByDay.set(bucket, 0);
    }
    for (const user of users) {
      const key = this.toDayKey(user.createdAt);
      const current = countByDay.get(key);
      if (current !== undefined) {
        countByDay.set(key, current + 1);
      }
    }
    return buckets.map((key) => ({
      timestamp: new Date(key + 'T00:00:00Z'),
      value: countByDay.get(key) ?? 0,
      label: key,
    }));
  }

  /** Build a daily conversion ratio series (orders/users per day). */
  private buildDailyConversionSeries(
    range: TimeRange,
    orders: Order[],
    users: User[],
  ): TimeSeriesPoint[] {
    const buckets = this.getDayBuckets(range);
    const ordersByDay = new Map<string, number>();
    const usersByDay = new Map<string, number>();
    for (const bucket of buckets) {
      ordersByDay.set(bucket, 0);
      usersByDay.set(bucket, 0);
    }
    for (const order of orders) {
      const key = this.toDayKey(order.createdAt);
      const current = ordersByDay.get(key);
      if (current !== undefined) {
        ordersByDay.set(key, current + 1);
      }
    }
    for (const user of users) {
      const key = this.toDayKey(user.createdAt);
      const current = usersByDay.get(key);
      if (current !== undefined) {
        usersByDay.set(key, current + 1);
      }
    }
    return buckets.map((key) => {
      const dayUsers = usersByDay.get(key) ?? 0;
      const dayOrders = ordersByDay.get(key) ?? 0;
      return {
        timestamp: new Date(key + 'T00:00:00Z'),
        value: dayUsers > 0 ? dayOrders / dayUsers : 0,
        label: key,
      };
    });
  }
}

