+    const buckets = this.getDayBuckets(range);
+    const ordersByDay = new Map<string, number>();
+    const usersByDay = new Map<string, number>();
+    for (const bucket of buckets) {
+      ordersByDay.set(bucket, 0);
+      usersByDay.set(bucket, 0);
+    }
+    for (const order of orders) {
+      const key = this.toDayKey(order.createdAt);
+      const current = ordersByDay.get(key);
+      if (current !== undefined) {
+        ordersByDay.set(key, current + 1);
+      }
+    }
+    for (const user of users) {
+      const key = this.toDayKey(user.createdAt);
